  {
    "id": "jordan-platitudes-bad",
    "persona": "jordan",
    "skill_chain": ["session-start"],
    "version": "v1-unhelpful",
    "turns": [
      {
        "role": "user",
        "content": "I'm Jordan, I moderate an open-source community. The project leads want to add an AI moderation bot and I've seen those go badly. We need a policy."
      },
